    _countBindGroupFormat: BindGroupFormat | null;
    /** @type {Compute|null} */
    _countCompute: Compute | null;
    /** @type {Shader|null} */
    _countShaderFisheye: Shader | null;
    /** @type {BindGroupFormat|null} */
    _countBindGroupFormatFisheye: BindGroupFormat | null;
    /** @type {Compute|null} */
    _countComputeFisheye: Compute | null;
    /** @type {Compute} */
    placeEntriesCompute: Compute;
    /** @type {Compute} */
    largeSplatCompute: Compute;
