    bucketSortCompute: Compute;
    /** @type {Compute} */
    copyCompute: Compute;
    /** @type {Compute} */
    chunkSortCompute: Compute;
    /** @type {Map<string, {shader: Shader, bindGroupFormat: BindGroupFormat, compute: Compute}>} */
    _rasterizeVariants: Map<string, {
        shader: Shader;
        bindGroupFormat: BindGroupFormat;
        compute: Compute;
    }>;
    /** @type {PrefixSumKernel} */
    prefixSumKernel: PrefixSumKernel;
