    _tileSplatCountsBuffer: StorageBuffer | null;
    /** @type {StorageBuffer|null} */
    _smallTileListBuffer: StorageBuffer | null;
    /** @type {StorageBuffer|null} */
    _largeTileListBuffer: StorageBuffer | null;
